package ui.employer;
import javax.swing.*;import java.awt.*;import controller.*;import dao.*;import model.*;import util.*;
public class CompanyProfilePanel extends JPanel{ JTextField name=UITheme.textField(),city=UITheme.textField(),address=UITheme.textField(),email=UITheme.textField(),phone=UITheme.textField(); JTextArea desc=new JTextArea(); EmployerController c=new EmployerController(); public CompanyProfilePanel(){ setBackground(UITheme.BG); setLayout(new GridLayout(0,1,0,8)); add(UITheme.title("Company Profile")); JTextField[] fs={name,city,address,email,phone}; String[] labs={"Company Name","City","Address","Email","Phone"}; for(int i=0;i<labs.length;i++){add(UITheme.label(labs[i]));add(fs[i]);} desc.setBackground(UITheme.PANEL_2);desc.setForeground(UITheme.TEXT); add(UITheme.label("Description"));add(new JScrollPane(desc)); JButton save=UITheme.button("Save Company Profile");add(save); load(); save.addActionListener(e->save());} Employer emp(){return new EmployerDAO().getByUserId(Session.getUserId());} void load(){Employer e=emp(); if(e==null)return; Company co=c.getCompany(e.getId()); if(co!=null){name.setText(co.getCompanyName());city.setText(co.getCity());address.setText(co.getAddress());email.setText(co.getEmail());phone.setText(co.getPhone());desc.setText(co.getDescription());}} void save(){Employer e=emp(); if(e==null){DialogUtil.error(this,"Employer profile missing");return;} boolean ok=c.saveCompany(new Company(0,e.getId(),name.getText(),desc.getText(),city.getText(),address.getText(),email.getText(),phone.getText(),false)); DialogUtil.success(this,ok?"Company profile saved. Wait for admin verification.":"Save failed");}}
